const token=flow.get('Enphase_local_token');
    const payload = token.split('.')[1];
    const decodedPayload = JSON.parse(Buffer.from(payload, 'base64').toString());
    msg.payload = {
        serialNumber: decodedPayload.aud,
        issuer: decodedPayload.iss,
        userType: decodedPayload.enphaseUser,
        expirationDate: new Date(decodedPayload.exp * 1000).toLocaleString(),
        createdAt: new Date(decodedPayload.iat * 1000).toLocaleString(),
        jti: decodedPayload.jti,
        username: decodedPayload.username
    };
    return msg;
